mapper.select:
select *
from report_record
where report_user_id = #{reportUserId}
  and report_type = #{reportType}
  and target_id = #{targetId}
limit 1

mapper.update:
update report_record
set status = #{status},
    handled_user_id = #{handledUserId},
    handled_time = #{handledTime}
where id = #{reportId}
  and status = 'pending'

update punishment_record
set status = 'lifted',
    end_time = #{handledTime}
where id = #{punishmentId}
  and status = 'active'
